#![cfg(unix)]
use std::sync::atomic::{AtomicI64, Ordering}; use std::sync::Once; use crate::eval::error::EvalError;
static TERMIOS_SAVED: AtomicI64 = AtomicI64::new(0); static TTY_FD: AtomicI64 = AtomicI64::new(-1); static mut SAVED_TERMIOS: [u8; 60] = [0u8; 60];
pub(crate) static WINSIZE_CHANGED: AtomicI64 = AtomicI64::new(1); pub(crate) static SIGCONT_ARRIVED: AtomicI64 = AtomicI64::new(0); static HOOKS_ONCE: Once = Once::new(); static WINSIZE_ONCE: Once = Once::new(); static JOBCTRL_ONCE: Once = Once::new();
fn restore_signal_safe() { if TERMIOS_SAVED.swap(0, Ordering::SeqCst) != 0 { let fd = TTY_FD.load(Ordering::SeqCst) as libc::c_int; if fd >= 0 { unsafe { libc::tcsetattr(fd, libc::TCSANOW, std::ptr::addr_of!(SAVED_TERMIOS) as *const libc::termios); } } } }
unsafe fn sa(sig: libc::c_int, h: extern "C" fn(libc::c_int), fl: libc::c_int) { let mut a: libc::sigaction = std::mem::zeroed(); a.sa_sigaction = h as *const () as usize; libc::sigemptyset(&mut a.sa_mask); a.sa_flags = fl; libc::sigaction(sig, &a, std::ptr::null_mut()); }
unsafe fn reraise(s: libc::c_int) { libc::signal(s, libc::SIG_DFL); let mut m: libc::sigset_t = std::mem::zeroed(); libc::sigemptyset(&mut m); libc::sigaddset(&mut m, s); libc::sigprocmask(libc::SIG_UNBLOCK, &m, std::ptr::null_mut()); libc::raise(s); }
extern "C" fn atexit_hook() { restore_signal_safe(); } extern "C" fn sig_handler(s: libc::c_int) { restore_signal_safe(); unsafe { reraise(s); } }
extern "C" fn winsize_h(_: libc::c_int) { WINSIZE_CHANGED.store(1, Ordering::SeqCst); } extern "C" fn tstp_h(s: libc::c_int) { restore_signal_safe(); unsafe { reraise(s); sa(libc::SIGTSTP, tstp_h, libc::SA_RESTART); } } extern "C" fn cont_h(_: libc::c_int) { SIGCONT_ARRIVED.store(1, Ordering::SeqCst); }
macro_rules! once { ($o:expr, $b:block) => { $o.call_once(|| unsafe { $b }) }; }
pub fn install_hooks_once() { once!(HOOKS_ONCE, { libc::atexit(atexit_hook); for s in &[libc::SIGTERM, libc::SIGHUP, libc::SIGQUIT] { sa(*s, sig_handler, 0); } }); } pub fn install_winsize_handler() { once!(WINSIZE_ONCE, { sa(libc::SIGWINCH, winsize_h, libc::SA_RESTART); WINSIZE_CHANGED.store(1, Ordering::SeqCst); }); } pub fn install_jobctrl_handlers() { once!(JOBCTRL_ONCE, { sa(libc::SIGTSTP, tstp_h, libc::SA_RESTART); sa(libc::SIGCONT, cont_h, libc::SA_RESTART); }); }
pub fn hooks_installed_p() -> bool { HOOKS_ONCE.is_completed() } pub fn winsize_handler_installed_p() -> bool { WINSIZE_ONCE.is_completed() } pub fn jobctrl_handlers_installed_p() -> bool { JOBCTRL_ONCE.is_completed() } pub fn termios_saved_p() -> bool { TERMIOS_SAVED.load(Ordering::SeqCst) != 0 }
#[no_mangle] pub extern "C" fn nl_tty_saved_flag_ptr() -> *mut i64 { TERMIOS_SAVED.as_ptr() } #[no_mangle] pub extern "C" fn nl_tty_fd_ptr() -> *mut i64 { TTY_FD.as_ptr() } #[no_mangle] pub extern "C" fn nl_tty_saved_termios_ptr() -> *mut u8 { std::ptr::addr_of_mut!(SAVED_TERMIOS) as *mut u8 }
#[no_mangle] pub unsafe extern "C" fn nl_tty_memcpy_to_saved(src: *const u8) { std::ptr::copy_nonoverlapping(src, std::ptr::addr_of_mut!(SAVED_TERMIOS) as *mut u8, 60); } #[no_mangle] pub extern "C" fn nl_tty_raw_install_hooks() -> i64 { install_hooks_once(); 0 } #[no_mangle] pub extern "C" fn nl_tty_read_byte() -> i64 { let mut b=[0u8;1]; let n=unsafe{libc::read(0,b.as_mut_ptr() as *mut libc::c_void,1)}; if n==1{b[0] as i64}else{-1} }
pub fn raw_mode_enter() -> Result<(), EvalError> { match unsafe{crate::elisp_cc_spike::tty_raw_enter([0u8;60].as_mut_ptr())}{0=>Ok(()),-1=>Err(EvalError::internal("terminal-raw-mode-enter: tcgetattr failed")),_=>Err(EvalError::internal("terminal-raw-mode-enter: tcsetattr failed"))} } pub fn raw_mode_leave() -> Result<(), EvalError> { unsafe{crate::elisp_cc_spike::tty_raw_leave(nl_tty_saved_termios_ptr())}; Ok(()) }
pub fn stdin_byte_available(t: i32) -> Result<Option<u8>, EvalError> { match unsafe{crate::elisp_cc_spike::tty_stdin_byte_avail([0u8,0,0,0,1,0,0,0].as_mut_ptr(),t as i64)}{-2=>Err(EvalError::internal("read-stdin-byte-available: poll failed")),n if n<0=>Ok(None),b=>Ok(Some(b as u8))} } pub fn current_winsize() -> Option<(u16, u16)> { let p=unsafe{crate::elisp_cc_spike::tty_winsize_current([0u8;8].as_mut_ptr())}; if p<0{None}else{Some((((p>>16)&0xFFFF) as u16,(p&0xFFFF) as u16))} } pub fn take_winsize_changed() -> bool { unsafe{crate::elisp_cc_spike::tty_take_atomic(WINSIZE_CHANGED.as_ptr())!=0} } pub fn take_sigcont() -> bool { unsafe{crate::elisp_cc_spike::tty_take_atomic(SIGCONT_ARRIVED.as_ptr())!=0} }
